#include "interface.h"
#include <unordered_set>
#include <vector>
#include <cstdint>

namespace {
uint64_t mix(uint64_t hash, uint64_t value) {
  hash ^= value;
  hash *= 1099511628211ULL;
  return hash;
}
}

uint64_t prefix_cache_checksum(
    const std::vector<uint32_t>& sorted_cache_keys,
    const std::vector<uint32_t>& request_blocks,
    const std::vector<int>& request_offsets,
    uint32_t hash_space,
    int iters) {
  (void)hash_space;
  std::unordered_set<uint32_t> cache_set(sorted_cache_keys.begin(), sorted_cache_keys.end());

  std::size_t num_requests = 0;
  if (request_offsets.size() > 1) {
    num_requests = request_offsets.size() - 1;
  }
  std::vector<uint64_t> prefixes(num_requests);

  for (std::size_t r = 0; r < num_requests; ++r) {
    int start = request_offsets[r];
    int end = request_offsets[r + 1];
    uint64_t cnt = 0;
    for (int i = start; i < end; ++i) {
      if (cache_set.find(request_blocks[static_cast<std::size_t>(i)]) == cache_set.end()) {
        break;
      }
      ++cnt;
    }
    prefixes[r] = cnt;
  }

  uint64_t hash = 0;
  for (int iter = 0; iter < iters; ++iter) {
    hash = 1469598103934665603ULL;
    for (std::size_t i = 0; i < num_requests; ++i) {
      hash = mix(hash, prefixes[i]);
    }
  }
  return hash;
}
